/**
 * Multipart 'file' (required) + 'caption' (optional). Validation giống photo. 201 + Location header. Vet không tồn tại → 404.
 * @summary Upload photo to album
 */
export const uploadVetAlbumPhoto = (
  vetId: number,
  uploadVetAlbumPhotoBody: BodyType<UploadVetAlbumPhotoBody>,
  params?: UploadVetAlbumPhotoParams,
  signal?: AbortSignal,
) => {
  const formData = new FormData();
  formData.append(`file`, uploadVetAlbumPhotoBody.file);

  return apiMutator<VetAlbumPhotoResponse>({
    url: `/api/v1/vets/${vetId}/album`,
    method: 'POST',
    headers: { 'Content-Type': 'multipart/form-data' },
    data: formData,
    params,
    signal,
  });
};

